'use client';

import { useState, useEffect, useCallback } from 'react';

// Extend Window interface to include our global
declare global {
  interface Window {
    deferredInstallPrompt: BeforeInstallPromptEvent | null;
  }
}

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>;
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>;
}

export function usePWAInstall() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
  const [isInstalled, setIsInstalled] = useState(false);
  const [isInstallable, setIsInstallable] = useState(false);
  const [installRequested, setInstallRequested] = useState(false);

  const detectStandalone = useCallback(() => {
    if (typeof window === 'undefined') return false;
    return (
      window.matchMedia('(display-mode: standalone)').matches ||
      ((window.navigator as Navigator & { standalone?: boolean }).standalone ?? false)
    );
  }, []);

  useEffect(() => {
    // Only mark "installed" when app is actually running in standalone mode.
    if (detectStandalone()) {
      setIsInstalled(true);
      return;
    }

    // Check if we already have the prompt captured globally
    const checkForPrompt = () => {
      if (typeof window !== 'undefined' && window.deferredInstallPrompt) {
        setDeferredPrompt(window.deferredInstallPrompt);
        setIsInstallable(true);
        return true;
      }
      return false;
    };

    // Check immediately
    if (!checkForPrompt()) {
      // Poll for it since it might come after component mounts
      const interval = setInterval(() => {
        if (checkForPrompt()) {
          clearInterval(interval);
        }
      }, 500);

      // Stop polling after 10 seconds
      setTimeout(() => clearInterval(interval), 10000);

      return () => clearInterval(interval);
    }
  }, [detectStandalone]);

  useEffect(() => {
    const handleAppInstalled = () => {
      window.deferredInstallPrompt = null;
      setDeferredPrompt(null);
      setIsInstallable(false);
      setInstallRequested(true);
      setIsInstalled(detectStandalone());
    };

    window.addEventListener('appinstalled', handleAppInstalled);

    return () => {
      window.removeEventListener('appinstalled', handleAppInstalled);
    };
  }, [detectStandalone]);

  // Also listen for the event in case it fires after mount
  useEffect(() => {
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      const promptEvent = e as BeforeInstallPromptEvent;
      window.deferredInstallPrompt = promptEvent;
      setDeferredPrompt(promptEvent);
      setIsInstallable(true);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  const triggerInstall = useCallback(async () => {
    // Use the global prompt if available, otherwise use state
    const prompt = window.deferredInstallPrompt || deferredPrompt;
    
    if (!prompt) {
      console.log('[PWA] No install prompt available');
      return false;
    }

    try {
      await prompt.prompt();
      const { outcome } = await prompt.userChoice;
      
      if (outcome === 'accepted') {
        window.deferredInstallPrompt = null;
        setDeferredPrompt(null);
        setIsInstallable(false);
        setInstallRequested(true);
        console.log('[PWA] User accepted install');
      } else {
        console.log('[PWA] User dismissed install');
      }
      
      return outcome === 'accepted';
    } catch (err) {
      console.error('[PWA] Error triggering install:', err);
      return false;
    }
  }, [deferredPrompt]);

  return {
    isInstalled,
    isInstallable: isInstallable || (typeof window !== 'undefined' && !!window.deferredInstallPrompt),
    installRequested,
    triggerInstall,
    deferredPrompt,
  };
}
